def calculate_inflation_adjusted_price(initial_price, year, target_year):
    # Using US Bureau of Labor Statistics CPI inflation calculator (example values)
    # Note: Replace with actual CPI data for precise calculation
    inflation_rates = {
        (1966, 2025): 9.92,  # Approximate cumulative inflation from 1966 to 2025
    }
    key = (year, target_year)
    if key in inflation_rates:
        adjusted_price = initial_price * inflation_rates[key]
        return round(adjusted_price, 2)
    else:
        return "Inflation data not available for the specified years."

